@Test(expected = IllegalArgumentException.class) public void validatesKeysNotEmptyWithTabs() {
    Attribute attr = new Attribute("\t\t", "Check");
}

@Test(expected = IllegalArgumentException.class) public void validatesKeysNotEmptyWithMixedWhitespace() {
    Attribute attr = new Attribute(" \t \n ", "Check");
}

@Test public void validatesKeysWithLeadingTrailingSpaces() {
    Attribute attr = new Attribute("  key  ", "value", null);
    assertEquals("key", attr.getKey());
}
